184: func startNodeLifecycleController(ctx context.Context, controllerContext ControllerContext, controllerName string) (controller.Interface, bool, error) {
185: 	lifecycleController, err := lifecyclecontroller.NewNodeLifecycleController(
186: 		ctx,
187: 		controllerContext.InformerFactory.Coordination().V1().Leases(),
188: 		controllerContext.InformerFactory.Core().V1().Pods(),
189: 		controllerContext.InformerFactory.Core().V1().Nodes(),
190: 		controllerContext.InformerFactory.Apps().V1().DaemonSets(),
191: 		// node lifecycle controller uses existing cluster role from node-controller
192: 		controllerContext.ClientBuilder.ClientOrDie("node-controller"),
193: 		controllerContext.ComponentConfig.KubeCloudShared.NodeMonitorPeriod.Duration,
194: 		controllerContext.ComponentConfig.NodeLifecycleController.NodeStartupGracePeriod.Duration,
195: 		controllerContext.ComponentConfig.NodeLifecycleController.NodeMonitorGracePeriod.Duration,
196: 		controllerContext.ComponentConfig.NodeLifecycleController.NodeEvictionRate,
197: 		controllerContext.ComponentConfig.NodeLifecycleController.SecondaryNodeEvictionRate,
198: 		controllerContext.ComponentConfig.NodeLifecycleController.LargeClusterSizeThreshold,
199: 		controllerContext.ComponentConfig.NodeLifecycleController.UnhealthyZoneThreshold,
200: 	)
201: 	if err != nil {
202: 		return nil, true, err
203: 	}
204: 	go lifecycleController.Run(ctx)
205: 	return nil, true, nil
206: }
